#include <stdlib.h>

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int is_triangle(int a, int b, int c) {
    return (a + b > c) && (a + c > b) && (b + c > a);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int a[4][3];
        for (int i = 0; i < 4; i++) {
            for (int j = 0; j < 3; j++) {
                scanf("%d", &a[i][j]);
            }
        }
        int found = 0;
        for (int i = 0; i < 4; i++) {
            for (int j = 0; j < 3; j++) {
                for (int k = 0; k < 3; k++) {
                    if (j != k) {
                        int new_a = a[i][j] + a[(i + 1) % 4][k];
                        int new_b = a[i][(j + 1) % 3];
                        int new_c = a[(i + 1) % 4][(k + 1) % 3];
                        if (is_triangle(new_a, new_b, new_c)) {
                            found = 1;
                            break;
                        }
                    }
                }
                if (found) break;
            }
            if (found) break;
        }
        if (found) printf("Yes\n");
        else printf("No\n");
    }
    return 0;
}

