import java.util.Scanner;
public class Main {
    public static boolean is_triangle(int a, int b, int c) {
        return (a + b > c) && (a + c > b) && (b + c > a);
    }
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int[][] a = new int[4][3];
            for (int i = 0; i < 4; i++) {
                for (int j = 0; j < 3; j++) {
                    a[i][j] = sc.nextInt();
                }
            }
            boolean found = false;
            for (int i = 0; i < 4; i++) {
                for (int j = 0; j < 3; j++) {
                    for (int k = 0; k < 3; k++) {
                        if (j != k) {
                            int new_a = a[i][j] + a[(i + 1) % 4][k];
                            int new_b = a[i][(j + 1) % 3];
                            int new_c = a[(i + 1) % 4][(k + 1) % 3];
                            if (is_triangle(new_a, new_b, new_c)) {
                                found = true;
                                break;
                            }
                        }
                    }
                    if (found) break;
                }
                if (found) break;
            }
            if (found) System.out.println("Yes");
            else System.out.println("No");
        }
    }
}

